def test_gateway():
    """Test the gateway server functionality."""
    
    ids = tokenizer.encode(
            payload["prompt"],
            add_special_tokens=False
        )
    
    #import pdb; pdb.set_trace()
    
    response = requests.post(
        "http://localhost:8080/v1/completions",
        json=payload
    )
    
    
    print(response.json())


if __name__ == "__main__":
    test_gateway()
